/**
 * CSV Parser Library for TypeScript
 * Handles parsing, type coercion, filtering, and aggregation
 */

interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

interface CSVError {
  row: number;
  message: string;
}

interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>, index: number) => boolean): Record<string, any>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<string | number | null, Record<string, any>[]>;
}

/**
 * Coerce a string value to its appropriate type
 * Handles: numbers (int and float), booleans (true/false case-insensitive), nulls, strings
 */
function coerceValue(value: string): string | number | boolean | null {
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Try to parse as boolean (case-insensitive)
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Try to parse as number
  if (!isNaN(Number(value)) && value.trim() !== '') {
    const num = Number(value);
    return num;
  }

  // Return as string
  return value;
}

/**
 * Parse CSV field values from a line, respecting quotes and delimiters
 * Handles escaped quotes (two quotes in a row = one literal quote)
 */
function parseFields(
  line: string,
  delimiter: string = ',',
  quote: string = '"'
): string[] {
  const fields: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = i + 1 < line.length ? line[i + 1] : '';

    if (char === quote) {
      if (inQuotes && nextChar === quote) {
        // Escaped quote - add single quote and skip both
        currentField += quote;
        i += 2;
        continue;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
        continue;
      }
    }

    if (char === delimiter && !inQuotes) {
      // Field delimiter found (not inside quotes)
      fields.push(currentField);
      currentField = '';
      i++;
      continue;
    }

    // Regular character
    currentField += char;
    i++;
  }

  // Add the last field
  fields.push(currentField);

  return fields;
}

/**
 * Main CSV parsing function
 */
export function parseCSV(
  input: string,
  options: CSVOptions = {}
): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  const rows: Record<string, any>[] = [];
  const errors: CSVError[] = [];
  let headers: string[] = [];

  // Split into lines
  const lines = input.split(lineSeparator).filter(line => line.length > 0);

  if (lines.length === 0) {
    return {
      rows: [],
      headers: [],
      errors: [],
      filter: (predicate) => [],
      sum: (column) => 0,
      average: (column) => 0,
      count: () => 0,
      groupBy: (column) => new Map(),
    };
  }

  // Parse headers from first line
  try {
    const headerFields = parseFields(lines[0], delimiter, quote);
    headers = headerFields.map(field => field.trim());
  } catch (err) {
    errors.push({
      row: 1,
      message: `Failed to parse headers: ${err instanceof Error ? err.message : String(err)}`,
    });
    return {
      rows: [],
      headers: [],
      errors,
      filter: (predicate) => [],
      sum: (column) => 0,
      average: (column) => 0,
      count: () => 0,
      groupBy: (column) => new Map(),
    };
  }

  // Parse data rows
  for (let i = 1; i < lines.length; i++) {
    try {
      const fields = parseFields(lines[i], delimiter, quote);

      // Check for malformed row (column count mismatch)
      if (fields.length !== headers.length) {
        errors.push({
          row: i + 1,
          message: `Expected ${headers.length} columns, got ${fields.length}`,
        });
        continue;
      }

      // Build row object with type coercion
      const row: Record<string, any> = {};
      for (let j = 0; j < headers.length; j++) {
        const value = fields[j].trim();
        row[headers[j]] = coerceValue(value);
      }

      rows.push(row);
    } catch (err) {
      errors.push({
        row: i + 1,
        message: `Failed to parse row: ${err instanceof Error ? err.message : String(err)}`,
      });
    }
  }

  // Return result with methods
  return {
    rows,
    headers,
    errors,
    filter(predicate) {
      return rows.filter(predicate);
    },
    sum(column) {
      return rows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number') {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average(column) {
      const numValues = rows.filter(row => typeof row[column] === 'number');
      if (numValues.length === 0) return 0;
      const total = numValues.reduce((acc, row) => acc + (row[column] as number), 0);
      return total / numValues.length;
    },
    count() {
      return rows.length;
    },
    groupBy(column) {
      const groups = new Map<string | number | null, Record<string, any>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }
      return groups;
    },
  };
}

import { parseCSV } from './csv-parser';

/**
 * Simple assertion helper
 */
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEqual<T>(actual: T, expected: T, message: string): void {
  if (actual !== expected) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertDeepEqual(actual: any, expected: any, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

/**
 * Test suites
 */

// Test 1: Basic parsing
function testBasicParsing(): void {
  console.log('Test: Basic parsing');
  const csv = 'name,age,city\nJohn,30,NYC\nJane,28,LA';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertDeepEqual(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assertEqual(result.rows[0].name, 'John', 'First row name should be John');
  assertEqual(result.rows[1].name, 'Jane', 'Second row name should be Jane');
  console.log('✓ Basic parsing passed');
}

// Test 2: Quoted fields with commas
function testQuotedFieldsWithCommas(): void {
  console.log('Test: Quoted fields with commas');
  const csv = 'name,description,price\n"Smith, John","A product, very good",10.50\n"Doe, Jane","Another item, great",20.75';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(result.rows[0].name, 'Smith, John', 'Name with comma should be preserved');
  assertEqual(result.rows[0].description, 'A product, very good', 'Description with comma should be preserved');
  assertEqual(result.rows[1].name, 'Doe, Jane', 'Second row name with comma should be preserved');
  console.log('✓ Quoted fields with commas passed');
}

// Test 3: Escaped quotes
function testEscapedQuotes(): void {
  console.log('Test: Escaped quotes');
  const csv = 'name,quote\n"John","""Hello"" world"\n"Jane","No quotes here"';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(result.rows[0].quote, '"Hello" world', 'Escaped quotes should become single quotes');
  assertEqual(result.rows[1].quote, 'No quotes here', 'Regular text should work');
  console.log('✓ Escaped quotes passed');
}

// Test 4: Custom delimiters
function testCustomDelimiters(): void {
  console.log('Test: Custom delimiters');
  const csv = 'name;age;city\nJohn;30;NYC\nJane;28;LA';
  const result = parseCSV(csv, { delimiter: ';' });

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertDeepEqual(result.headers, ['name', 'age', 'city'], 'Headers should match with semicolon delimiter');
  assertEqual(result.rows[0].name, 'John', 'Data should parse with semicolon delimiter');
  console.log('✓ Custom delimiters passed');
}

// Test 5: Custom line separator
function testCustomLineSeparator(): void {
  console.log('Test: Custom line separator');
  const csv = 'name,age\r\nJohn,30\r\nJane,28';
  const result = parseCSV(csv, { lineSeparator: '\r\n' });

  assertEqual(result.rows.length, 2, 'Should have 2 rows with CRLF separator');
  assertEqual(result.rows[0].name, 'John', 'First row should parse correctly');
  console.log('✓ Custom line separator passed');
}

// Test 6: Type coercion - integers
function testTypeCoercionIntegers(): void {
  console.log('Test: Type coercion - integers');
  const csv = 'name,age\nJohn,30\nJane,28';
  const result = parseCSV(csv);

  assertEqual(typeof result.rows[0].age, 'number', 'Age should be coerced to number');
  assertEqual(result.rows[0].age, 30, 'Age value should be 30');
  assertEqual(result.rows[1].age, 28, 'Second age should be 28');
  console.log('✓ Type coercion - integers passed');
}

// Test 7: Type coercion - floats
function testTypeCoercionFloats(): void {
  console.log('Test: Type coercion - floats');
  const csv = 'name,price\nItem1,10.50\nItem2,20.75';
  const result = parseCSV(csv);

  assertEqual(typeof result.rows[0].price, 'number', 'Price should be coerced to number');
  assertEqual(result.rows[0].price, 10.5, 'Price value should be 10.5');
  console.log('✓ Type coercion - floats passed');
}

// Test 8: Type coercion - booleans
function testTypeCoercionBooleans(): void {
  console.log('Test: Type coercion - booleans');
  const csv = 'name,active,verified\nJohn,true,FALSE\nJane,TRUE,false';
  const result = parseCSV(csv);

  assertEqual(result.rows[0].active, true, 'true should become boolean true');
  assertEqual(result.rows[0].verified, false, 'FALSE should become boolean false');
  assertEqual(result.rows[1].active, true, 'TRUE should become boolean true');
  assertEqual(result.rows[1].verified, false, 'false should become boolean false');
  console.log('✓ Type coercion - booleans passed');
}

// Test 9: Type coercion - nulls
function testTypeCoercionNulls(): void {
  console.log('Test: Type coercion - nulls');
  const csv = 'name,age,note\nJohn,,\nJane,null,NULL\nBob,25,something';
  const result = parseCSV(csv);

  assertEqual(result.rows[0].age, null, 'Empty string should become null');
  assertEqual(result.rows[0].note, null, 'Empty string should become null');
  assertEqual(result.rows[1].age, null, 'null string should become null');
  assertEqual(result.rows[1].note, null, 'NULL string should become null');
  assertEqual(result.rows[2].age, 25, 'Valid number should remain number');
  assertEqual(result.rows[2].note, 'something', 'Regular string should remain string');
  console.log('✓ Type coercion - nulls passed');
}

// Test 10: Type coercion - strings
function testTypeCoercionStrings(): void {
  console.log('Test: Type coercion - strings');
  const csv = 'name,description\nJohn,hello world\nJane,123abc';
  const result = parseCSV(csv);

  assertEqual(typeof result.rows[0].name, 'string', 'Name should be string');
  assertEqual(typeof result.rows[0].description, 'string', 'Description should be string');
  assertEqual(result.rows[1].description, '123abc', 'Mixed alphanumeric should be string');
  console.log('✓ Type coercion - strings passed');
}

// Test 11: Malformed row error collection
function testMalformedRowErrorCollection(): void {
  console.log('Test: Malformed row error collection');
  const csv = 'name,age,city\nJohn,30\nJane,28,LA,extra\nBob,25,NYC';
  const result = parseCSV(csv);

  assertEqual(result.errors.length, 2, 'Should collect 2 errors');
  assertEqual(result.rows.length, 1, 'Should only have 1 valid row (Bob)');
  assertEqual(result.rows[0].name, 'Bob', 'Valid row should still be parsed');
  assertEqual(result.errors[0].row, 2, 'First error should be at row 2');
  assertEqual(result.errors[1].row, 3, 'Second error should be at row 3');
  console.log('✓ Malformed row error collection passed');
}

// Test 12: Filter functionality
function testFilterFunctionality(): void {
  console.log('Test: Filter functionality');
  const csv = 'name,age\nJohn,30\nJane,28\nBob,35';
  const result = parseCSV(csv);

  const filtered = result.filter(row => (row.age as number) > 29);
  assertEqual(filtered.length, 2, 'Should have 2 rows with age > 29');
  assertEqual(filtered[0].name, 'John', 'John should be in filtered results');
  assertEqual(filtered[1].name, 'Bob', 'Bob should be in filtered results');
  console.log('✓ Filter functionality passed');
}

// Test 13: Sum aggregation
function testSumAggregation(): void {
  console.log('Test: Sum aggregation');
  const csv = 'product,quantity\nApple,5\nBanana,3\nOrange,7';
  const result = parseCSV(csv);

  const total = result.sum('quantity');
  assertEqual(total, 15, 'Sum of quantities should be 15');
  console.log('✓ Sum aggregation passed');
}

// Test 14: Average aggregation
function testAverageAggregation(): void {
  console.log('Test: Average aggregation');
  const csv = 'product,price\nApple,10\nBanana,5\nOrange,15';
  const result = parseCSV(csv);

  const avg = result.average('price');
  assertEqual(avg, 10, 'Average of prices should be 10');
  console.log('✓ Average aggregation passed');
}

// Test 15: Count aggregation
function testCountAggregation(): void {
  console.log('Test: Count aggregation');
  const csv = 'name,age\nJohn,30\nJane,28\nBob,35';
  const result = parseCSV(csv);

  const count = result.count();
  assertEqual(count, 3, 'Count should be 3');
  console.log('✓ Count aggregation passed');
}

// Test 16: GroupBy aggregation
function testGroupByAggregation(): void {
  console.log('Test: GroupBy aggregation');
  const csv = 'category,item,price\nFruit,Apple,10\nFruit,Banana,5\nVegetable,Carrot,3\nVegetable,Lettuce,2';
  const result = parseCSV(csv);

  const grouped = result.groupBy('category');
  assertEqual(grouped.size, 2, 'Should have 2 groups');
  assertEqual(grouped.get('Fruit')!.length, 2, 'Fruit group should have 2 items');
  assertEqual(grouped.get('Vegetable')!.length, 2, 'Vegetable group should have 2 items');
  assertEqual(grouped.get('Fruit')![0].item, 'Apple', 'First fruit item should be Apple');
  console.log('✓ GroupBy aggregation passed');
}

// Test 17: Empty input
function testEmptyInput(): void {
  console.log('Test: Empty input');
  const csv = '';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 0, 'Should have 0 rows');
  assertEqual(result.headers.length, 0, 'Should have 0 headers');
  assertEqual(result.errors.length, 0, 'Should have 0 errors');
  assertEqual(result.count(), 0, 'Count should be 0');
  console.log('✓ Empty input passed');
}

// Test 18: Single column
function testSingleColumn(): void {
  console.log('Test: Single column');
  const csv = 'name\nJohn\nJane\nBob';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 3, 'Should have 3 rows');
  assertEqual(result.headers.length, 1, 'Should have 1 header');
  assertDeepEqual(result.headers, ['name'], 'Header should be name');
  console.log('✓ Single column passed');
}

// Test 19: Single row
function testSingleRow(): void {
  console.log('Test: Single row');
  const csv = 'name,age,city\nJohn,30,NYC';
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, 'Should have 1 row');
  assertEqual(result.rows[0].name, 'John', 'Row should have correct data');
  console.log('✓ Single row passed');
}

// Test 20: Very large fields
function testVeryLargeFields(): void {
  console.log('Test: Very large fields');
  const largeText = 'a'.repeat(10000);
  const csv = `name,description\nJohn,"${largeText}"`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, 'Should have 1 row');
  assertEqual(result.rows[0].description, largeText, 'Large field should be preserved');
  console.log('✓ Very large fields passed');
}

// Test 21: Special characters in quoted fields
function testSpecialCharactersInQuotedFields(): void {
  console.log('Test: Special characters in quoted fields');
  const csv = 'name,comment\n"John","Special chars: !@#$%^&*()"\n"Jane","Unicode: café"';
  const result = parseCSV(csv);

  assertEqual(result.rows[0].comment, 'Special chars: !@#$%^&*()', 'Special characters should be preserved');
  assertEqual(result.rows[1].comment, 'Unicode: café', 'Unicode characters should be preserved');
  console.log('✓ Special characters in quoted fields passed');
}

// Test 22: Multiple escaped quotes in a row
function testMultipleEscapedQuotes(): void {
  console.log('Test: Multiple escaped quotes in a row');
  const csv = 'name,text\n"John","He said ""Hello"" and ""Goodbye"""\n"Jane","""Quoted"""';
  const result = parseCSV(csv);

  assertEqual(
    result.rows[0].text,
    'He said "Hello" and "Goodbye"',
    'Multiple escaped quotes should be handled'
  );
  assertEqual(result.rows[1].text, '"Quoted"', 'Quotes at start and end should work');
  console.log('✓ Multiple escaped quotes in a row passed');
}

// Test 23: Whitespace handling
function testWhitespaceHandling(): void {
  console.log('Test: Whitespace handling');
  const csv = 'name , age , city\n  John  ,  30  ,  NYC  ';
  const result = parseCSV(csv);

  assertEqual(result.headers[0], 'name', 'Headers should be trimmed');
  assertEqual(result.rows[0].name, 'John', 'Values should be trimmed');
  assertEqual(result.rows[0].age, 30, 'Numeric values should be trimmed and coerced');
  console.log('✓ Whitespace handling passed');
}

// Test 24: Filter with index
function testFilterWithIndex(): void {
  console.log('Test: Filter with index');
  const csv = 'name,age\nJohn,30\nJane,28\nBob,35';
  const result = parseCSV(csv);

  const filtered = result.filter((row, index) => index < 2);
  assertEqual(filtered.length, 2, 'Should filter by index');
  assertEqual(filtered[0].name, 'John', 'First row should be John');
  assertEqual(filtered[1].name, 'Jane', 'Second row should be Jane');
  console.log('✓ Filter with index passed');
}

// Test 25: Average with mixed types
function testAverageWithMixedTypes(): void {
  console.log('Test: Average with mixed types');
  const csv = 'item,value\nA,10\nB,invalid\nC,20\nD,30';
  const result = parseCSV(csv);

  const avg = result.average('value');
  assertEqual(avg, 20, 'Average should only count numeric values (10+20+30)/3 = 20');
  console.log('✓ Average with mixed types passed');
}

// Test 26: GroupBy with null values
function testGroupByWithNullValues(): void {
  console.log('Test: GroupBy with null values');
  const csv = 'category,name\nFruit,Apple\n,Unknown\nVegetable,Carrot\n,Another';
  const result = parseCSV(csv);

  const grouped = result.groupBy('category');
  assertEqual(grouped.size, 3, 'Should have 3 groups including null');
  assertEqual(grouped.get(null)!.length, 2, 'Null group should have 2 items');
  console.log('✓ GroupBy with null values passed');
}

// Test 27: Sum with null values
function testSumWithNullValues(): void {
  console.log('Test: Sum with null values');
  const csv = 'item,quantity\nA,5\nB,\nC,10';
  const result = parseCSV(csv);

  const total = result.sum('quantity');
  assertEqual(total, 15, 'Sum should ignore null values');
  console.log('✓ Sum with null values passed');
}

// Test 28: Custom quote character
function testCustomQuoteCharacter(): void {
  console.log('Test: Custom quote character');
  const csv = "name,description\nJohn,'Hello, world'\nJane,'Test''s quote'";
  const result = parseCSV(csv, { quote: "'" });

  assertEqual(result.rows[0].description, 'Hello, world', 'Should parse with custom quote character');
  assertEqual(result.rows[1].description, "Test's quote", 'Should handle escaped custom quotes');
  console.log('✓ Custom quote character passed');
}

// Test 29: Complex scenario with all features
function testComplexScenario(): void {
  console.log('Test: Complex scenario with all features');
  const csv = `name,age,active,salary,department
"Smith, John",30,true,50000.50,Engineering
"Doe, Jane",,false,,HR
"Johnson, Bob",45,TRUE,75000,Engineering
"Williams, Alice",28,FALSE,45000.25,"Sales & Marketing"`;

  const result = parseCSV(csv);

  assertEqual(result.rows.length, 4, 'Should have 4 rows');
  assertEqual(result.rows[0].name, 'Smith, John', 'Quoted names with commas should work');
  assertEqual(result.rows[0].age, 30, 'Numbers should be coerced');
  assertEqual(result.rows[0].active, true, 'Booleans should be coerced');
  assertEqual(result.rows[1].age, null, 'Empty values should be null');
  assertEqual(result.rows[3].department, 'Sales & Marketing', 'Quoted fields with ampersand should work');

  const filtered = result.filter(r => r.active === true);
  assertEqual(filtered.length, 2, 'Filter should work on coerced booleans');

  const avgSalary = result.average('salary');
  assertEqual(avgSalary, 57500.25, 'Average should calculate correctly with mixed nulls');

  console.log('✓ Complex scenario passed');
}

/**
 * Run all tests
 */
function runAllTests(): void {
  console.log('\n========== Running CSV Parser Tests ==========\n');

  const tests = [
    testBasicParsing,
    testQuotedFieldsWithCommas,
    testEscapedQuotes,
    testCustomDelimiters,
    testCustomLineSeparator,
    testTypeCoercionIntegers,
    testTypeCoercionFloats,
    testTypeCoercionBooleans,
    testTypeCoercionNulls,
    testTypeCoercionStrings,
    testMalformedRowErrorCollection,
    testFilterFunctionality,
    testSumAggregation,
    testAverageAggregation,
    testCountAggregation,
    testGroupByAggregation,
    testEmptyInput,
    testSingleColumn,
    testSingleRow,
    testVeryLargeFields,
    testSpecialCharactersInQuotedFields,
    testMultipleEscapedQuotes,
    testWhitespaceHandling,
    testFilterWithIndex,
    testAverageWithMixedTypes,
    testGroupByWithNullValues,
    testSumWithNullValues,
    testCustomQuoteCharacter,
    testComplexScenario,
  ];

  let passed = 0;
  let failed = 0;

  for (const test of tests) {
    try {
      test();
      passed++;
    } catch (err) {
      failed++;
      console.error(`✗ ${test.name} failed:`);
      console.error(`  ${err instanceof Error ? err.message : String(err)}`);
    }
  }

  console.log(`\n========== Test Results ==========`);
  console.log(`Total: ${tests.length}`);
  console.log(`Passed: ${passed}`);
  console.log(`Failed: ${failed}`);
  console.log(`=====================================\n`);

  if (failed > 0) {
    process.exit(1);
  }
}

runAllTests();

